#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int x, y, z;
        scanf("%d %d %d", &x, &y, &z);
        int best = 0;
        for (int mask = 0; mask < 8; ++mask) {
            int useR = ((mask & 1) != 0) + ((mask & 4) != 0); // RG and RB
            int useG = ((mask & 1) != 0) + ((mask & 2) != 0); // RG and GB
            int useB = ((mask & 2) != 0) + ((mask & 4) != 0); // GB and RB
            if (useR <= x && useG <= y && useB <= z) {
                int cnt = 0;
                if (x - useR > 0) ++cnt;
                if (y - useG > 0) ++cnt;
                if (z - useB > 0) ++cnt;
                // number of secondary colours produced = popcount(mask)
                cnt += (mask & 1) + ((mask >> 1) & 1) + ((mask >> 2) & 1);
                if (cnt > best) best = cnt;
            }
        }
        printf("%d\n", best);
    }
    return 0;
}

