#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        x = int(next(it)); y = int(next(it)); z = int(next(it))
        best = 0
        for mask in range(8):
            useR = ((mask>>0)&1) + ((mask>>2)&1)
            useG = ((mask>>0)&1) + ((mask>>1)&1)
            useB = ((mask>>1)&1) + ((mask>>2)&1)
            if useR <= x and useG <= y and useB <= z:
                cnt = (1 if x-useR>0 else 0) + (1 if y-useG>0 else 0) + (1 if z-useB>0 else 0)
                cnt += bin(mask).count('1')
                if cnt > best:
                    best = cnt
        out.append(str(best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

